fn load_vectors() -> Option<Vec<Vector>> {
    let path = vectors_path();
    if !path.exists() {
        eprintln!("skipping repo-level BID codec vectors; missing {}", path.display());
        return None;
    }
    let data = fs::read_to_string(&path).expect("failed to read vectors.json");
    let file: VectorFile = serde_json::from_str(&data).expect("failed to parse vectors.json");
    assert_eq!(
        file.format_version, EXPECTED_FORMAT_VERSION,
        "unsupported BID codec vectors format_version"
    );
    Some(file.vectors)
}

